131: func makeLokiError(bytes []byte) error {
132: 	var data lokiError
133: 	err := json.Unmarshal(bytes, &data)
134: 	if err != nil {
135: 		// we were unable to convert the bytes to JSON, we return the whole text
136: 		return fmt.Errorf("%v", string(bytes))
137: 	}
138: 
139: 	if data.Message == "" {
140: 		// we got no usable error message, we return the whole text
141: 		return fmt.Errorf("%v", string(bytes))
142: 	}
143: 
144: 	return fmt.Errorf("%v", data.Message)
145: }
146: 
147: // we know there is an error,
148: // based on the http-response-body
149: // we have to make an informative error-object
150: func readLokiError(body io.ReadCloser) error {
151: 	var buf bytes.Buffer
152: 	_, err := buf.ReadFrom(body)
153: 	if err != nil {
154: 		return err
155: 	}
156: 
157: 	bytes := buf.Bytes()
158: 
159: 	// the error-message is probably a JSON structure,
160: 	// with a string-field named "message". we want the
161: 	// value of that field.
162: 	// but, the response might be just a simple string,
163: 	// this was used in older Loki versions.
164: 	// so our approach is this:
165: 	// - we try to convert the bytes to JSON
166: 	// - we take the value of the field "message"
167: 	// - if any of these steps fail, or if "message" is empty, we return the whole text
168: 
169: 	return makeLokiError(bytes)
170: }
