270: func (api *LokiAPI) RawQuery(ctx context.Context, resourcePath string) (RawLokiResponse, error) {
271: 	api.log.Debug("Sending raw query to loki", "resourcePath", resourcePath)
272: 	req, err := makeRawRequest(ctx, api.url, resourcePath)
273: 	if err != nil {
274: 		api.log.Debug("Failed to prepare request to loki", "error", err, "resourcePath", resourcePath)
275: 		return RawLokiResponse{}, err
276: 	}
277: 	start := time.Now()
278: 	resp, err := api.client.Do(req)
279: 	if err != nil {
280: 		status := "error"
281: 		if errors.Is(err, context.Canceled) {
282: 			status = "cancelled"
283: 		}
284: 		lp := []any{"error", err, "resourcePath", resourcePath, "status", status, "duration", time.Since(start), "stage", stageDatabaseRequest}
285: 		if resp != nil {
286: 			lp = append(lp, "statusCode", resp.StatusCode)
287: 		}
288: 		api.log.Debug("Error received from Loki", lp...)
289: 		return RawLokiResponse{}, err
290: 	}
291: 
292: 	defer func() {
293: 		if err := resp.Body.Close(); err != nil {
294: 			api.log.Warn("Failed to close response body", "error", err)
295: 		}
296: 	}()
297: 
298: 	api.log.Info("Response received from loki", "status", "ok", "statusCode", resp.StatusCode, "contentLength", resp.Header.Get("Content-Length"), "duration", time.Since(start), "contentEncoding", resp.Header.Get("Content-Encoding"), "stage", stageDatabaseRequest)
299: 
300: 	// server errors are handled by the plugin-proxy to hide the error message
301: 	if resp.StatusCode/100 == 5 {
302: 		return RawLokiResponse{}, readLokiError(resp.Body)
303: 	}
304: 
305: 	body, err := io.ReadAll(resp.Body)
306: 	if err != nil {
307: 		api.log.Debug("Error reading response body bytes", "error", err)
308: 		return RawLokiResponse{}, err
309: 	}
310: 
311: 	// client errors are passed as a json struct to the client
312: 	if resp.StatusCode/100 != 2 {
313: 		lokiResponseErr := lokiResponseError{Message: makeLokiError(body).Error()}
314: 		api.log.Warn("Non 200 HTTP status received from loki", "error", lokiResponseErr.Message, "statusCode", resp.StatusCode, "resourcePath", resourcePath)
315: 		traceID := tracing.TraceIDFromContext(ctx, false)
316: 		if traceID != "" {
317: 			lokiResponseErr.TraceID = traceID
318: 		}
319: 		body, err = json.Marshal(lokiResponseErr)
320: 		if err != nil {
321: 			return RawLokiResponse{
322: 				Status: resp.StatusCode,
323: 			}, err
324: 		}
325: 	}
326: 
327: 	rawLokiResponse := RawLokiResponse{
328: 		Body:     body,
329: 		Status:   resp.StatusCode,
330: 		Encoding: resp.Header.Get("Content-Encoding"),
331: 	}
332: 
333: 	return rawLokiResponse, nil
334: }
