359: // setXScopeOrgIDHeader sets the `X-Scope-OrgID` header in the provided HTTP request based on the tenant ID retrieved from the context.
360: // `X-Scope-OrgID` is needed by the Loki system to work in multi-tenant mode.
361: // See https://github.com/grafana/loki/blob/main/docs/sources/operations/multi-tenancy.md
362: func setXScopeOrgIDHeader(req *http.Request, ctx context.Context) *http.Request {
363: 	logger := backend.NewLoggerWith("logger", "tsdb.loki")
364: 
365: 	md, ok := metadata.FromIncomingContext(ctx)
366: 	if !ok {
367: 		// Metadata are currently set and needed only locally for multi-tenancy, while on cloud
368: 		// this is set by our stack
369: 		logger.Debug("Metadata not present in context. Header not set")
370: 		return req
371: 	}
372: 
373: 	tenantids := md.Get("tenantid")
374: 	if len(tenantids) == 0 {
375: 		// We assume we are not using multi-tenant mode, which is fine
376: 		logger.Debug("Tenant ID not present. Header not set")
377: 	} else if len(tenantids) > 1 {
378: 		// Loki supports multiple tenant IDs, but we should receive them from different contexts
379: 		logger.Error(strconv.Itoa(len(tenantids)) + " tenant IDs found. Header not set")
380: 	} else {
381: 		req.Header.Add("X-Scope-OrgID", tenantids[0])
382: 		logger.Debug("Tenant ID " + tenantids[0] + " added to Loki request")
383: 	}
384: 	return req
385: }
